  {
    "name": "Hyphenated_Organisations",
    "description": "Matches hyphenated organisation names with mandatory suffix, handling 'u.' and '+' separators, ensuring the name part is valid.",
    "format": "regex",
    "content": "\\b([A-Z][a-zA-Z\\u00e4\\u00f6\\u00fc\\u00c4\\u00d6\\u00dc\\u00df]+(?:\\s+u\\.\\s+[A-Z][a-zA-Z\\u00e4\\u00f6\\u00fc\\u00c4\\u00d6\\u00dc\\u00df]+|\\s+\\+\\s+[A-Z][a-zA-Z\\u00e4\\u00f6\\u00fc\\u00c4\\u00d6\\u00dc\\u00df]+|\\-[A-Z][a-zA-Z\\u00e4\\u00f6\\u00fc\\u00c4\\u00d6\\u00dc\\u00df]+(?:\\s+[A-Z][a-zA-Z\\u00e4\\u00f6\\u00fc\\u00c4\\u00d6\\u00dc\\u00df]+)?)?)\\s+(GmbH|AG|Ges\\.m\\.b\\.H\\.|Limited|Holding)\\b",
    "priority": 10,
    "output_template": {
      "text": "$0",
      "start": "$start",
      "end": "$end",
      "type": "organisation"
    },
    "output_key": "entities",
    "user_feedback": [
      "Organisation names often consist of two or more capitalised words before the legal suffix. Rules must capture multi-word names like Wiener Stadtwerke GmbH or \u00d6sterreichische Post AG."
    ]
  },
